/**
 * api.js — the data access layer. This is the ONLY file that knows where
 * destination data lives. To migrate to Supabase (or any backend) later,
 * change the implementations here — every page/component goes through
 * these functions and needs no edits.
 *
 * Current backend: static JSON files generated by scripts/build-json-data.js
 *   data/destinations/<slug>.json   full detail for one destination
 *   data/destinations/index.json    lightweight manifest + site meta
 *   data/search-index.json          AI-finder text index
 */

const BASE = 'data';
const cache = new Map();

function getJSON(path) {
  if (cache.has(path)) return cache.get(path);
  const p = fetch(path).then((r) => {
    if (!r.ok) throw new Error('HTTP ' + r.status + ' loading ' + path);
    return r.json();
  });
  cache.set(path, p);
  p.catch(() => cache.delete(path)); // allow retry after a failed fetch
  return p;
}

/** Full detail for one destination. The detail page loads ONLY this. */
export function fetchDestination(slug) {
  return getJSON(BASE + '/destinations/' + encodeURIComponent(slug) + '.json');
}

/**
 * Lightweight manifest: { count, meta: {priceTiers, types, states, months},
 * destinations: [summary…] }. Used by list/browse pages — never the full data.
 */
export function fetchIndex() {
  return getJSON(BASE + '/destinations/index.json');
}

/** AI-finder text index: { entries: [{slug, placeNames, hotelNames, tiers, hay}…] } */
export function fetchSearchIndex() {
  return getJSON(BASE + '/search-index.json');
}

/** Summary record for one slug from the manifest (null if unknown). */
export async function fetchSummary(slug) {
  const idx = await fetchIndex();
  return idx.destinations.find((d) => d.slug === slug) || null;
}
